column6:
"IF ISAUTHORIZE.HTTP_CODE==200 THEN
DEBUG_INFO:='AUTHORIZED';
DEBUG(DEBUG_INFO);
$.GPARAM.CODE:=ISAUTHORIZE.VALUE.code;
GETGRANTTOKEN.F:=1;
POLLTOKENACTIVE:=0;
ELSE
DEBUG_INFO:=ISAUTHORIZE.VALUE.error_description;
DEBUG(DEBUG_INFO);
ENDIF;"

"BEARER:='Bearer';
IF GETGRANTTOKEN.HTTP_CODE==200 && ISEQUAL(GETGRANTTOKEN.VALUE.token_type,BEARER) THEN
DEBUG_INFO:='ACCESS TOKEN RECEIVED!';
X.50 := 'Zugriffstoken erhalten!';
GETAPPLIANCES.F := 1;
$.GPARAM.AUTH_INFO:=DEBUG_INFO;
DEBUG(DEBUG_INFO);
$.GPARAM.ACCESS_TOKEN:=GETGRANTTOKEN.VALUE.access_token;
$.GPARAM.EXPIRES_IN:=GETGRANTTOKEN.VALUE.expires_in;
$.GPARAM.ID_TOKEN:=GETGRANTTOKEN.VALUE.id_token;
$.GPARAM.REFRESH_TOKEN:=GETGRANTTOKEN.VALUE.refresh_token;
$.GPARAM.TOKEN_TYPE:=GETGRANTTOKEN.VALUE.token_type;
$.GPARAM.EXPIRES_DATE:=(GETGRANTTOKEN.VALUE.expires_in/10*9)+$.SYS.TIME;
$.GPARAM.REFRESH_COUNT:=$.GPARAM.REFRESH_COUNT+1;
POLLTOKENACTIVE:=0;
SAVE_JSON($.GPARAM.ACCESS_TOKEN,$.GPARAM.EXPIRES_IN,$.GPARAM.ID_TOKEN,$.GPARAM.REFRESH_TOKEN,$.GPARAM.TOKEN_TYPE,$.GPARAM.EXPIRES_DATE,$.GPARAM.REFRESH_COUNT);
ELSE IF GETGRANTTOKEN.HTTP_CODE>=400 THEN
DEBUG_INFO:=GETGRANTTOKEN.VALUE.error_description;
$.GPARAM.AUTH_INFO:=DEBUG_INFO;
DEBUG(DEBUG_INFO);
ENDIF;
GETGRANTTOKEN.F:=0;"

"BEARER:='Bearer';
IF REFRESHTOKEN.HTTP_CODE==200 && ISEQUAL(REFRESHTOKEN.VALUE.token_type,BEARER) THEN
DEBUG_INFO:='ACCESS TOKEN RECEIVED!';
$.GPARAM.AUTH_INFO:=DEBUG_INFO;
DEBUG(DEBUG_INFO);
$.GPARAM.ACCESS_TOKEN:=REFRESHTOKEN.VALUE.access_token;
$.GPARAM.EXPIRES_IN:=REFRESHTOKEN.VALUE.expires_in;
$.GPARAM.ID_TOKEN:=REFRESHTOKEN.VALUE.id_token;
$.GPARAM.REFRESH_TOKEN:=REFRESHTOKEN.VALUE.refresh_token;
$.GPARAM.TOKEN_TYPE:=REFRESHTOKEN.VALUE.token_type;
$.GPARAM.REFRESH_COUNT:=$.GPARAM.REFRESH_COUNT+1;
$.GPARAM.EXPIRES_DATE:=(REFRESHTOKEN.VALUE.expires_in/10*9)+$.SYS.TIME;
POLLTOKENACTIVE:=0;
SAVE_JSON($.GPARAM.ACCESS_TOKEN,$.GPARAM.EXPIRES_IN,$.GPARAM.ID_TOKEN,$.GPARAM.REFRESH_TOKEN,$.GPARAM.TOKEN_TYPE,$.GPARAM.EXPIRES_DATE,$.GPARAM.REFRESH_COUNT);
ELSE IF REFRESHTOKEN.HTTP_CODE>=400 THEN
DEBUG_INFO:=REFRESHTOKEN.VALUE.error_description;
$.GPARAM.AUTH_INFO:=DEBUG_INFO;
DEBUG(DEBUG_INFO);
ENDIF;
REFRESHTOKEN.F:=0;"

"IF GETAPPLIANCES.HTTP_CODE==200  THEN
$.GPARAM.SLAVELIST:=GETAPPLIANCES.VALUE.[0].gatewayDevices[0];
DEBUG($.GPARAM.SLAVELIST);
$.GPARAM.REFRESH_COUNT:=$.GPARAM.REFRESH_COUNT+1;
ELSE
DEBUG_INFO:='FEHLER';
DEBUG(DEBUG_INFO);
ENDIF;
DEBUG(GETAPPLIANCES.HTTP_DATA);"

"IF GETDATA.HTTP_CODE == 200 THEN
    X.10 := GETDATA.VALUE.managementPoints[1].name.value;
    X.11 := GETDATA.VALUE.managementPoints[0].modelInfo.value;
    X.13 := GETDATA.VALUE.isCloudConnectionUp.value;
    X.14 := GETDATA.VALUE.managementPoints[1].isInErrorState.value;
    X.15 := GETDATA.VALUE.managementPoints[1].errorCode.value;
    X.16 := GETDATA.VALUE.timestamp;
    X.17 := GETDATA.VALUE.managementPoints[0].ipAddress.value;
    X.18 := GETDATA.VALUE.managementPoints[0].macAddress.value;
    X.20 := GETDATA.VALUE.managementPoints[1].sensoryData.value.roomTemperature.value;
    X.21 := GETDATA.VALUE.managementPoints[1].sensoryData.value.outdoorTemperature.value;
    X.22 := GETDATA.VALUE.managementPoints[1].onOffMode.value;
    X.23 := GETDATA.VALUE.managementPoints[1].operationMode.value;
    X.28 := GETDATA.VALUE.managementPoints[1].powerfulMode.value;
    X.50 := '-';
    X.52 := 1;
ELSE
    DEBUG(GETDATA.VALUE.error_description);
    DEBUG(GETDATA.HTTP_DATA);
    DEBUG(GETDATA.VALUE.message);
    X.50 := GETDATA.VALUE.message;
    X.52 := 2;
   ENDIF;
IF (GETDATA.HTTP_CODE == 200) && ISEQUAL(GETDATA.VALUE.managementPoints[1].operationMode.value,'auto') THEN
    X.40 := GETDATA.VALUE.managementPoints[1].temperatureControl.value.operationModes.auto.setpoints.roomTemperature.value;
    X.41 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.auto.fanSpeed.currentMode.value;
    X.42 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.auto.fanSpeed.modes.fixed.value;
    X.43 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.auto.fanDirection.horizontal.currentMode.value;
    X.44 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.auto.fanDirection.vertical.currentMode.value;
ELSE IF (GETDATA.HTTP_CODE == 200) && ISEQUAL(GETDATA.VALUE.managementPoints[1].operationMode.value,'dry') THEN
    X.40 := GETDATA.VALUE.managementPoints[1].temperatureControl.value.operationModes.dry.setpoints.roomTemperature.value;
    X.41 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.dry.fanSpeed.currentMode.value;
    X.42 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.dry.fanSpeed.modes.fixed.value;
    X.43 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.dry.fanDirection.horizontal.currentMode.value;
    X.44 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.dry.fanDirection.vertical.currentMode.value;
ELSE IF (GETDATA.HTTP_CODE == 200) && ISEQUAL(GETDATA.VALUE.managementPoints[1].operationMode.value,'cooling') THEN
    X.40 := GETDATA.VALUE.managementPoints[1].temperatureControl.value.operationModes.cooling.setpoints.roomTemperature.value;
    X.41 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.cooling.fanSpeed.currentMode.value;
    X.42 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.cooling.fanSpeed.modes.fixed.value;
    X.43 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.cooling.fanDirection.horizontal.currentMode.value;
    X.44 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.cooling.fanDirection.vertical.currentMode.value;
ELSE IF (GETDATA.HTTP_CODE == 200) && ISEQUAL(GETDATA.VALUE.managementPoints[1].operationMode.value,'heating') THEN
    X.40 := GETDATA.VALUE.managementPoints[1].temperatureControl.value.operationModes.heating.setpoints.roomTemperature.value;
    X.41 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.heating.fanSpeed.currentMode.value;
    X.42 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.heating.fanSpeed.modes.fixed.value;
    X.43 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.heating.fanDirection.horizontal.currentMode.value;
    X.44 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.heating.fanDirection.vertical.currentMode.value;
ELSE IF (GETDATA.HTTP_CODE == 200) && ISEQUAL(GETDATA.VALUE.managementPoints[1].operationMode.value,'fanOnly') THEN
    X.40 := GETDATA.VALUE.managementPoints[1].temperatureControl.value.operationModes.fanOnly.setpoints.roomTemperature.value;
    X.41 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.fanOnly.fanSpeed.currentMode.value;
    X.42 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.fanOnly.fanSpeed.modes.fixed.value;
    X.43 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.fanOnly.fanDirection.horizontal.currentMode.value;
    X.44 := GETDATA.VALUE.managementPoints[1].fanControl.value.operationModes.fanOnly.fanDirection.vertical.currentMode.value;
ENDIF;
X.46 := X.20 * 10;
X.47 := X.21 * 10;
X.48 := X.40 * 10;
GETDATA.F := 0;"

