"SETSTATE.F := 1;
IF X.60 == 1 THEN
    SONOFF := 'on';
ELSE IF X.60 == 2 THEN
    SONOFF := 'off';
ENDIF;
X.60 := 0;"

"IF ( X.61 == 2 ) THEN
    TMP_ID:=SYSTEMINFO(ID);
    TMP_RANDOM:=RANDOMSTRING(10);
    $.GPARAM.CONTROLLER_UID:=CONCAT(TMP_ID,TMP_RANDOM);
   AUTHORIZE.F:=1;
